  ('dietitian-moex-10344', 'dietitian', 'dietitian-moex-095-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '鮮乳或生乳經加熱殺菌後，於無菌狀態重新加入預先培養的乳酸菌，使乳糖分解生成乳酸進一步使乳蛋白質沉澱的現 象稱為下列何者？', '["腐敗", "發酵", "劣變", "變敗"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "3d09d9a5ef46", "answer_pdf_sha1": "489405e1aca8", "source_family": "moex-gov-tw", "moex": {"exam_code": "095140", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "095", "exam_name": "095年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
